// Native bridge shim, exposed to the CRM source files as `window.BPP.native`.
//
// The 11 CRM source files reach cross-file identifiers as globals (window.*),
// so this file follows the same pattern globals-setup.js uses: import the
// npm-bundled Capacitor plugins here, then pin a stable interface onto
// window that a JSX file can call from anywhere, e.g.:
//
//   window.BPP.native.haptics.impact('light');
//   window.BPP.native.statusBar.setBpp();
//   await window.BPP.native.preferences.get('key');
//
// Every method is safe on the web (returns a resolved promise or no-ops)
// so the same source file works identically as a PWA in Safari and as the
// Capacitor iOS app. Whether we are actually running natively is decided
// once at load time via Capacitor.isNativePlatform(); no per-call re-check.

import { Capacitor } from '@capacitor/core';
import { App as CapApp } from '@capacitor/app';
import { Haptics, ImpactStyle, NotificationType } from '@capacitor/haptics';
import { StatusBar, Style as StatusBarStyle } from '@capacitor/status-bar';
import { SplashScreen } from '@capacitor/splash-screen';
import { Preferences } from '@capacitor/preferences';
import { Keyboard, KeyboardResize, KeyboardStyle } from '@capacitor/keyboard';
import { Camera, CameraResultType, CameraSource } from '@capacitor/camera';
import { Share } from '@capacitor/share';

const isNative = Capacitor.isNativePlatform();
const platform = Capacitor.getPlatform();

const NAVY = '#1B2B4B';

const impactStyleFor = (s) => {
  if (s === 'heavy') return ImpactStyle.Heavy;
  if (s === 'medium') return ImpactStyle.Medium;
  return ImpactStyle.Light;
};

const notificationTypeFor = (t) => {
  if (t === 'warning') return NotificationType.Warning;
  if (t === 'error') return NotificationType.Error;
  return NotificationType.Success;
};

const native = {
  isNative,
  platform,

  haptics: {
    async impact(style) {
      if (!isNative) return;
      try { await Haptics.impact({ style: impactStyleFor(style) }); } catch (_) { /* no-op */ }
    },
    async selection() {
      if (!isNative) return;
      try { await Haptics.selectionChanged(); } catch (_) { /* no-op */ }
    },
    async notify(type) {
      if (!isNative) return;
      try { await Haptics.notification({ type: notificationTypeFor(type) }); } catch (_) { /* no-op */ }
    },
  },

  statusBar: {
    async setBpp() {
      if (!isNative) return;
      try {
        // overlaysWebView: true is set in capacitor.config.json so the
        // webview extends edge-to-edge and the CRM's own env(safe-area-
        // inset-*) padding handles the notch + home indicator. Setting
        // overlay=true at runtime here reasserts it after any plugin
        // race so we never lose the config-time value.
        await StatusBar.setOverlaysWebView({ overlay: true });
        // Style.Light = "the style is light" = DARK CONTENT (dark text
        // + icons on a light background). The CRM shell's near-white
        // (#f4f6f9) paints under the status bar via the overlay, so
        // dark content is what's readable. Style.Dark (light content /
        // white text) would disappear against the shell.
        await StatusBar.setStyle({ style: StatusBarStyle.Light });
      } catch (_) { /* no-op */ }
    },
    async hide() {
      if (!isNative) return;
      try { await StatusBar.hide(); } catch (_) { /* no-op */ }
    },
    async show() {
      if (!isNative) return;
      try { await StatusBar.show(); } catch (_) { /* no-op */ }
    },
  },

  splash: {
    async hide() {
      if (!isNative) return;
      try { await SplashScreen.hide({ fadeOutDuration: 200 }); } catch (_) { /* no-op */ }
    },
  },

  preferences: {
    async get(key) {
      if (!isNative) {
        try { return localStorage.getItem(key); } catch (_) { return null; }
      }
      try { const { value } = await Preferences.get({ key }); return value; } catch (_) { return null; }
    },
    async set(key, value) {
      if (!isNative) {
        try { localStorage.setItem(key, value); } catch (_) { /* no-op */ }
        return;
      }
      try { await Preferences.set({ key, value }); } catch (_) { /* no-op */ }
    },
    async remove(key) {
      if (!isNative) {
        try { localStorage.removeItem(key); } catch (_) { /* no-op */ }
        return;
      }
      try { await Preferences.remove({ key }); } catch (_) { /* no-op */ }
    },
  },

  keyboard: {
    async hide() {
      if (!isNative) return;
      try { await Keyboard.hide(); } catch (_) { /* no-op */ }
    },
  },


  camera: {
    async pickPhoto({ source = 'prompt', quality = 82 } = {}) {
      if (!isNative) {
        return { error: 'web-fallback', message: 'Native camera only in the app. Use the file input on web.' };
      }
      const cameraSource =
        source === 'camera' ? CameraSource.Camera :
        source === 'library' ? CameraSource.Photos :
        CameraSource.Prompt;
      try {
        const photo = await Camera.getPhoto({
          quality,
          allowEditing: false,
          resultType: CameraResultType.DataUrl,
          source: cameraSource,
          saveToGallery: false,
          correctOrientation: true,
        });
        return { dataUrl: photo.dataUrl, format: photo.format };
      } catch (e) {
        return { error: e && e.message ? e.message : 'camera-cancelled' };
      }
    },
  },

  share: {
    async send({ title, text, url }) {
      const payload = {};
      if (title) payload.title = title;
      if (text) payload.text = text;
      if (url) payload.url = url;
      if (!isNative) {
        if (typeof navigator !== 'undefined' && navigator.share) {
          try { await navigator.share(payload); return { ok: true, path: 'web-share' }; } catch (_) { return { ok: false, path: 'web-share-cancelled' }; }
        }
        return { ok: false, path: 'unsupported' };
      }
      try { await Share.share(payload); return { ok: true, path: 'native-share' }; } catch (_) { return { ok: false, path: 'native-share-cancelled' }; }
    },
  },

  app: {
    onBack(handler) {
      if (!isNative) return () => {};
      try {
        const promise = CapApp.addListener('backButton', () => { try { handler(); } catch (_) { /* no-op */ } });
        return async () => {
          try { const sub = await promise; sub.remove(); } catch (_) { /* no-op */ }
        };
      } catch (_) { return () => {}; }
    },
    onResume(handler) {
      if (!isNative) return () => {};
      try {
        const promise = CapApp.addListener('resume', () => { try { handler(); } catch (_) { /* no-op */ } });
        return async () => {
          try { const sub = await promise; sub.remove(); } catch (_) { /* no-op */ }
        };
      } catch (_) { return () => {}; }
    },
  },
};

if (typeof window !== 'undefined') {
  window.BPP = window.BPP || {};
  window.BPP.native = native;
}

// One-time native-only setup on load: theme the status bar, then hide the
// splash screen once the CRM has had a beat to boot. On web this whole block
// is a no-op via the isNative check inside each method.
if (isNative) {
  // Mark native so Ionic CSS can stop keying body height off lagging --vvh
  // (that double-snap: keyboard animates, then composer jumps ~1s later).
  try { document.documentElement.classList.add('bpp-native'); } catch (_) { /* no-op */ }

  native.statusBar.setBpp();
  // Give the CRM ~1s to render its first paint before pulling the splash;
  // the SplashScreen plugin's own launchShowDuration (900ms) is the ceiling.
  setTimeout(() => { native.splash.hide(); }, 1000);

  // Keyboard: LIGHT = frosted system keyboard (DARK was the solid black slab).
  // resize none = WKWebView stays full-bleed so the frosted keyboard overlays
  // the thread (Key wants translucent-over-content, not a hard shrink). We
  // lift ion-app ourselves via --kb-h at keyboardWillShow, which fires at
  // animation START. Capacitor's resize:ionic was still delivering the bar
  // ~1s late (Key 2026-07-13). Runtime call so live-reload picks it up
  // without a native rebuild; capacitor.config mirrors for cold launches.
  (async () => {
    try {
      await Keyboard.setStyle({ style: KeyboardStyle.Light });
      await Keyboard.setResizeMode({ mode: KeyboardResize.None });
    } catch (_) { /* no-op */ }
  })();

  // Drive --kb-h from willShow at animation start. CSS translates ion-footer /
  // ion-tab-bar over ~250ms (iOS keyboard curve) so the message bar rises WITH
  // the keyboard. Do NOT use Capacitor resize:ionic: Keyboard.m delays
  // _updateFrame by (animationDuration + 0.2s), the late snap Key saw.
  //
  // Hide lifecycle is SPLIT (critic 2026-07-13): willHide only animates
  // --kb-h to 0; didHide restores safe-area / kb-open. Clearing chin padding
  // on willHide made the composer jump ~34px early while the transform was
  // still running.
  //
  // Boot clearKb: never inherit a stuck pad from a prior live-reload.
  const applyKb = (kb, opts) => {
    const root = document.documentElement;
    const h = Math.max(0, kb || 0);
    // willShow: ignore QuickType blips. didShow: accept any positive height
    // so a late accessory-bar settle can refine the pad.
    if (!(opts && opts.fromDidShow) && h < 40) return;
    if (h <= 0) return;
    root.setAttribute('data-bpp-kb', '1');
    root.classList.add('kb-open');
    root.style.setProperty('--vvs', '0px');
    root.style.setProperty('--kb-h', h + 'px');
    // Keep the last thread rows visible above the lifted composer. Double rAF
    // so --padding-bottom: var(--kb-h) (ionic-bpp-theme) has applied before
    // scrollToBottom measures the content end (clipped-last-message scar).
    try {
      const content = document.querySelector('ion-router-outlet ion-content, ion-content');
      if (content && typeof content.scrollToBottom === 'function') {
        requestAnimationFrame(() => {
          requestAnimationFrame(() => {
            try { content.scrollToBottom(180); } catch (_) { /* no-op */ }
          });
        });
      }
    } catch (_) { /* no-op */ }
    // Mid-page / modal fields: scroll the focused control above the keyboard.
    try {
      const active = document.activeElement;
      if (active && (active.tagName === 'INPUT' || active.tagName === 'TEXTAREA' || active.isContentEditable)) {
        requestAnimationFrame(() => {
          try { active.scrollIntoView({ block: 'center', inline: 'nearest' }); } catch (_) { /* no-op */ }
        });
      }
    } catch (_) { /* no-op */ }
  };
  const beginHideKb = () => {
    // Animate pad down with the keyboard; keep kb-open so chin padding stays
    // off until didHide.
    document.documentElement.style.setProperty('--kb-h', '0px');
  };
  const clearKb = () => {
    const root = document.documentElement;
    root.removeAttribute('data-bpp-kb');
    root.style.setProperty('--kb-h', '0px');
    root.style.setProperty('--vvs', 'env(safe-area-inset-bottom)');
    root.classList.remove('kb-open');
  };
  clearKb();
  try {
    Keyboard.addListener('keyboardWillShow', (info) => {
      applyKb((info && info.keyboardHeight) || 0);
    });
    Keyboard.addListener('keyboardDidShow', (info) => {
      applyKb((info && info.keyboardHeight) || 0, { fromDidShow: true });
    });
    Keyboard.addListener('keyboardWillHide', () => { beginHideKb(); });
    Keyboard.addListener('keyboardDidHide', () => { clearKb(); });
  } catch (_) { /* no-op */ }
  try {
    window.addEventListener('keyboardWillShow', (ev) => {
      let kb = 0;
      try {
        const d = ev && (ev.keyboardHeight != null ? ev : (typeof ev.data === 'string' ? JSON.parse(ev.data.replace(/'/g, '"')) : ev.data));
        kb = (d && d.keyboardHeight) || 0;
      } catch (_) { kb = 0; }
      applyKb(kb);
    });
    window.addEventListener('keyboardDidShow', (ev) => {
      let kb = 0;
      try {
        const d = ev && (ev.keyboardHeight != null ? ev : (typeof ev.data === 'string' ? JSON.parse(ev.data.replace(/'/g, '"')) : ev.data));
        kb = (d && d.keyboardHeight) || 0;
      } catch (_) { kb = 0; }
      applyKb(kb, { fromDidShow: true });
    });
    window.addEventListener('keyboardWillHide', () => { beginHideKb(); });
    window.addEventListener('keyboardDidHide', () => { clearKb(); });
  } catch (_) { /* no-op */ }

  // Stuck-pad recovery without visualViewport (dead under resize:none): if
  // focus leaves every text field while data-bpp-kb is set, clear after a
  // short beat so Cmd+K / lost willHide cannot leave the composer floating.
  try {
    document.addEventListener('focusout', () => {
      setTimeout(() => {
        if (document.documentElement.getAttribute('data-bpp-kb') !== '1') return;
        const a = document.activeElement;
        const typing = a && (a.tagName === 'INPUT' || a.tagName === 'TEXTAREA' || a.isContentEditable);
        if (!typing) clearKb();
      }, 320);
    });
  } catch (_) { /* no-op */ }

  // The CRM's --vvh convention was built for mobile Safari, where
  // visualViewport.height shrinks with the URL bar / keyboard. Capacitor's
  // WKWebView has neither URL bar nor unexpected visual-viewport shrinkage
  // outside a real keyboard: the visualViewport height at rest is the FULL
  // native window height. On some launches the CRM's setVVH() ran before the
  // WKWebView had finished sizing (Capacitor lays out just after DOMContent
  // ready), so --vvh got locked to a slightly-too-short value and the shell
  // ended up floating above the actual bottom of the screen with a strip
  // of WKWebView background showing under it. Re-fire the CRM's setVVH so
  // it picks up the settled size, and keep firing it on orientation change
  // so a rotate lands correctly too. Also force one more tick after 300ms
  // in case a splash-teardown or plugin re-layout nudges the viewport late.
  // Skip rewriting --vvh while the keyboard is open: we own the lift via
  // --kb-h + footer/tab-bar transform; a late visualViewport tick must not
  // fight it.
  const resync = () => {
    try {
      if (document.documentElement.getAttribute('data-bpp-kb') === '1') return;
      if (document.documentElement.classList.contains('kb-open')) return;
      const vv = window.visualViewport;
      const h = vv ? vv.height : window.innerHeight;
      const w = window.innerWidth;
      document.documentElement.style.setProperty('--vvh', h + 'px');
      document.documentElement.style.setProperty('--vvw', w + 'px');
    } catch (_) { /* no-op */ }
  };
  window.addEventListener('load', resync);
  window.addEventListener('orientationchange', resync);
  setTimeout(resync, 300);
  setTimeout(resync, 1200);
}
