// BPP CRM entry point (Vite build).
//
// The load-order contract with the pre-Vite index.html was:
//   1. React / ReactDOM / Supabase load as UMD globals (window.React, ...).
//   2. Twilio Voice SDK loads (window.Twilio).
//   3. The 11 CRM source files execute in a fixed sequence, each populating
//      its exports via `Object.assign(window, {...})` at end-of-file.
//   4. crm-app.jsx (last) calls ReactDOM.createRoot(...).render(<Root />).
//
// This entry point reproduces that contract inside a Vite ES module graph:
//   - './globals-setup.js' runs FIRST and pins the npm-bundled React /
//     ReactDOM / Supabase onto window (equivalent to the UMD script tags).
//     It's its own module because ES `import` statements execute in the order
//     declared but all before any non-import statement in the SAME module, so
//     doing the window pins inline here would have them fire AFTER the source
//     files' imports (which is the "React is not defined" trap).
//   - The 11 side-effect imports below run in the exact same order the old
//     <script> tags did. Each file continues to reach cross-file identifiers
//     via `window.X` (either explicit or via the browser's bare-identifier
//     fallback to global), so no source-file rewiring is required and the
//     conversion is byte-behavior-identical.
//   - The Twilio Voice SDK still loads via a plain <script> tag in index.html
//     (`window.Twilio`), not through this graph, because it's vendored UMD.

import { Capacitor } from '@capacitor/core';
import './globals-setup.js';
import './native-setup.js';
import './uitest-bridge.js';

// Branch (2026-07-10): ?ionic=1 boots the Ionic surface on the web. On a real
// Capacitor install (iPhone) AND the Tauri Mac app, Ionic is the default,
// the whole point of the native shells is the Ionic remake. Without this, a
// fresh App.app / BPP.app load has no query string and silently boots the
// old bespoke CRM (Key scar 2026-07-13). Dynamic imports so only one tree
// loads. globals-setup ran above.
function isTauriShell() {
  try {
    if (typeof document !== 'undefined' &&
        document.documentElement &&
        document.documentElement.getAttribute('data-bpp-shell') === 'tauri') {
      return true;
    }
    return !!(window.__TAURI_INTERNALS__ || window.__TAURI__ || window.__TAURI_METADATA__);
  } catch (_) {
    return false;
  }
}
const wantIonic =
  new URLSearchParams(location.search).get('ionic') === '1' ||
  Capacitor.isNativePlatform() ||
  isTauriShell();
// Vite scar (P0 2026-07-13, blank Mac CRM): a bare if/else of two dynamic
// imports was compiled into ONE ternary that shared a single
// __vite__mapDeps([...]) array pointing at the bespoke crm-boot deps only.
// The ionic-app-*.css chunk was never modulepreloaded / injected, so
// ion-app stayed at the custom-element default (display:inline, 0x0) and
// the dual-pane tab bars stacked on a blank white pane. Keep each import
// behind its own function so Rollup emits separate preload dep lists and
// the Ionic CSS chunk actually loads with ?ionic=1.
function bootIonic() {
  return import('./ionic-app.jsx');
}
function bootBespoke() {
  return import('./crm-boot.js');
}
if (wantIonic) bootIonic();
else bootBespoke();
