// UI-test bridge, NATIVE-ONLY, for driving the CRM in the iOS simulator by
// DOM selector instead of by fragile pixel coordinates.
//
// WHY THIS EXISTS
// Auditing the real app on the simulator (real safe zones, real keyboard,
// real WKWebView) needs a way to tap/focus/scroll reliably. Pixel taps via
// AppleScript are brittle (they break when the window moves, the device
// changes, or iOS shifts layout) and kept mis-firing. This bridge receives
// commands over a `bpp://uitest?...` deep link (delivered by
// `xcrun simctl openurl booted "bpp://uitest?cmd=..."`) and performs them
// against the live DOM. It clicks the REAL elements, so the app's real
// onClick / haptics / navigation all fire exactly as for a human, but the
// target is chosen by visible text or CSS selector, which is deterministic.
//
// SAFETY / GATING
// - Registers ONLY when Capacitor.isNativePlatform() is true. On the web
//   (backuppowerpro.com/crm/v3/) this file's listener never attaches, so the
//   live customer-adjacent web build has ZERO exposure to it.
// - Only acts on URLs whose host is exactly `uitest`; real future deep links
//   (bpp://contact/123) pass through untouched.
// - The CRM is an operator-only tool (Key's device), not a customer page, so
//   a test deep-link handler on the native app is low-risk. To strip it for a
//   locked-down release, delete the one `import './uitest-bridge.js'` line in
//   main.jsx and rebuild.
//
// COMMAND VOCABULARY (bpp://uitest?cmd=<verb>:<arg>)
//   tap:text=<visible text>     click the smallest element containing the text
//   tap:sel=<css selector>      click the first element matching the selector
//   focus:sel=<css selector>    focus an input/textarea (raises the keyboard)
//   focus:text=<label text>     focus the input nearest a label containing text
//   scroll:top | scroll:bottom  scroll the main scroll container
//   scroll:sel=<css selector>   scrollIntoView the matching element
//   back                        click a visible Back affordance if present
//   ping                        write a marker to the DOM (liveness check)
// Multiple commands can be chained with a `;` between them, e.g.
//   bpp://uitest?cmd=tap:text=Finance;scroll:top

import { Capacitor } from '@capacitor/core';
import { App as CapApp } from '@capacitor/app';

const isNative = Capacitor.isNativePlatform();

// Small on-screen toast so a screenshot shows the bridge acted + what it did.
function bridgeToast(msg, ok) {
  try {
    let el = document.getElementById('__bpp_uitest_toast');
    if (!el) {
      el = document.createElement('div');
      el.id = '__bpp_uitest_toast';
      el.style.cssText =
        'position:fixed;left:8px;bottom:8px;z-index:2147483647;max-width:60vw;' +
        'font:600 10px/1.35 JetBrains Mono,monospace;padding:5px 8px;border-radius:7px;' +
        'pointer-events:none;white-space:pre-wrap;opacity:0.92;';
      document.body.appendChild(el);
    }
    // Ride above the lifted chrome / keyboard so soak frames are not
    // confused by a green strip peeking under a translucent keyboard.
    let bottom = 8;
    try {
      const kb = document.documentElement.style.getPropertyValue('--kb-h') || '0px';
      const n = parseFloat(kb) || 0;
      if (n > 0) bottom = Math.round(n + 12);
    } catch (_) { /* no-op */ }
    el.style.bottom = bottom + 'px';
    el.style.background = ok ? 'rgba(16,88,52,0.92)' : 'rgba(140,24,24,0.92)';
    el.style.color = '#fff';
    el.textContent = 'UITEST ' + msg;
  } catch (_) { /* no-op */ }
}

// Find the smallest element whose trimmed textContent contains `text`
// (case-insensitive). "Smallest" = fewest descendants, so we click the leaf
// button/label, not a giant wrapping container.
function findByText(text) {
  const needle = text.trim().toLowerCase();
  const all = Array.from(document.querySelectorAll(
    'button, a, [role="button"], [role="tab"], ion-item, ion-tab-button, ion-button, ion-back-button, ion-chip, span, div, label, li'
  ));
  const matches = all.filter((el) => {
    const t = (el.textContent || '').trim().toLowerCase();
    return t.includes(needle) && t.length < needle.length + 80; // ion-item rows carry badges
  });
  if (!matches.length) return null;
  // Prefer the one with the fewest element descendants (most leaf-like), then
  // the one that is actually a clickable role.
  matches.sort((a, b) => {
    const clickA = a.matches('button,a,[role="button"],[role="tab"],ion-item,ion-tab-button,ion-button,ion-back-button') ? 0 : 1;
    const clickB = b.matches('button,a,[role="button"],[role="tab"],ion-item,ion-tab-button,ion-button,ion-back-button') ? 0 : 1;
    if (clickA !== clickB) return clickA - clickB;
    return a.querySelectorAll('*').length - b.querySelectorAll('*').length;
  });
  return matches[0];
}

// Climb to the nearest clickable ancestor (button / role=button / role=tab),
// because React onClick is often on a wrapper of the text node we matched.
function clickableAncestor(el) {
  let node = el;
  for (let i = 0; i < 6 && node; i++) {
    if (node.matches && node.matches('button, a, [role="button"], [role="tab"], ion-item, ion-tab-button, ion-button, ion-back-button')) return node;
    node = node.parentElement;
  }
  return el;
}

function doTap(arg) {
  let el = null;
  if (arg.startsWith('text=')) el = findByText(arg.slice(5));
  else if (arg.startsWith('sel=')) {
    const sel = arg.slice(4);
    el = document.querySelector(sel);
    // Ionic often keeps `tab` as a JS property without reflecting the attribute.
    if (!el && sel.includes('ion-tab-button')) {
      const m = /tab=["']([^"']+)["']/.exec(sel);
      if (m) {
        el = Array.from(document.querySelectorAll('ion-tab-button'))
          .find((n) => {
            if ((n.getAttribute('tab') || n.tab) !== m[1]) return false;
            try {
              const r = n.getBoundingClientRect();
              return r.width >= 2 && r.height >= 2;
            } catch (_) { return true; }
          }) || null;
      }
    }
  }
  if (!el) { bridgeToast('tap MISS ' + arg, false); return false; }
  // Prefer a visible host (thread routes hide the browse tab bar; a hidden
  // leftover node must not eat the tap and no-op the soak).
  try {
    const r = el.getBoundingClientRect();
    if (r.width < 2 || r.height < 2) {
      bridgeToast('tap MISS hidden ' + arg, false);
      return false;
    }
  } catch (_) { /* no-op */ }
  const target = clickableAncestor(el);
  target.scrollIntoView({ block: 'center' });
  target.click();
  bridgeToast('tap ' + arg, true);
  return true;
}

function doFocus(arg) {
  let el = null;
  if (arg.startsWith('sel=')) el = document.querySelector(arg.slice(4));
  else if (arg.startsWith('text=')) {
    const label = findByText(arg.slice(5));
    if (label) el = label.querySelector('input, textarea') ||
      (label.closest('label') && label.closest('label').querySelector('input, textarea'));
  }
  if (!el) { bridgeToast('focus MISS ' + arg, false); return false; }
  el.scrollIntoView({ block: 'center' });
  el.focus();
  // Some browsers need a click to raise the software keyboard reliably.
  try { el.click(); } catch (_) { /* no-op */ }
  bridgeToast('focus ' + arg, true);
  return true;
}

function mainScroller() {
  // The CRM's scroll containers are inline-styled overflow:auto panes; pick
  // the tallest scrollable one as "the list".
  const candidates = Array.from(document.querySelectorAll('div'))
    .filter((d) => d.scrollHeight > d.clientHeight + 40 &&
      ['auto', 'scroll'].includes(getComputedStyle(d).overflowY));
  candidates.sort((a, b) => (b.clientHeight) - (a.clientHeight));
  return candidates[0] || document.scrollingElement || document.body;
}

function doScroll(arg) {
  if (arg === 'top') { const s = mainScroller(); s.scrollTo({ top: 0 }); bridgeToast('scroll top', true); return true; }
  if (arg === 'bottom') { const s = mainScroller(); s.scrollTo({ top: s.scrollHeight }); bridgeToast('scroll bottom', true); return true; }
  if (arg.startsWith('sel=')) {
    const el = document.querySelector(arg.slice(4));
    if (!el) { bridgeToast('scroll MISS ' + arg, false); return false; }
    el.scrollIntoView({ block: 'center' });
    bridgeToast('scroll ' + arg, true);
    return true;
  }
  return false;
}

function runCommand(cmd) {
  const [verb, ...rest] = cmd.split(':');
  const arg = rest.join(':');
  switch (verb) {
    case 'tap': return doTap(arg);
    case 'focus': return doFocus(arg);
    case 'scroll': return doScroll(arg);
    case 'back': {
      // IonBackButton hosts its label in shadow DOM; text search often misses.
      // Prefer the host / defaultHref button, then aria, then visible text.
      const b =
        document.querySelector('ion-back-button') ||
        document.querySelector('ion-button[router-direction="back"]') ||
        document.querySelector('[aria-label*="Back" i], [data-back]') ||
        findByText('Back');
      if (b) {
        const t = clickableAncestor(b);
        // ion-back-button needs a click on the host; also try shadow button.
        const inner = (b.shadowRoot && b.shadowRoot.querySelector('button')) || t;
        (inner || t).click();
        bridgeToast('back', true);
        return true;
      }
      bridgeToast('back MISS', false); return false;
    }
    case 'kb': {
      // Drive --kb-h directly (native keyboard lift path) for Simulator QA
      // without relying on Cmd+K firing UIKeyboard notifications.
      const px = Math.max(0, parseInt(arg, 10) || 0);
      const root = document.documentElement;
      if (px > 0) {
        root.setAttribute('data-bpp-kb', '1');
        root.classList.add('kb-open');
        root.style.setProperty('--vvs', '0px');
        root.style.setProperty('--kb-h', px + 'px');
        try {
          const content = document.querySelector('ion-router-outlet ion-content, ion-content');
          if (content && typeof content.scrollToBottom === 'function') {
            requestAnimationFrame(() => { try { content.scrollToBottom(120); } catch (_) { /* no-op */ } });
          }
        } catch (_) { /* no-op */ }
      } else {
        root.removeAttribute('data-bpp-kb');
        root.style.setProperty('--kb-h', '0px');
        root.style.setProperty('--vvs', 'env(safe-area-inset-bottom)');
        root.classList.remove('kb-open');
      }
      bridgeToast('kb ' + px, true);
      return true;
    }
    case 'goto': {
      // Full navigation under the CRM base; preserves ?ionic=1&test=1.
      // Always hard-assign so a stuck thread route cannot leave the soak
      // without a browse tab bar (THREAD EXCEPTION hides ion-tab-bar).
      const path = arg.startsWith('/') ? arg : '/' + arg;
      try {
        const params = new URLSearchParams(location.search || '');
        params.set('ionic', params.get('ionic') || '1');
        if (!params.has('test') && /[?&]test=1/.test(location.search)) params.set('test', '1');
        if (!params.has('test') && /test=1/.test(String(location.href))) params.set('test', '1');
        // Fixture mode is the soak default when already on a test URL.
        if (!params.has('test') && document.documentElement.getAttribute('data-bpp-test') === '1') {
          params.set('test', '1');
        }
        const qs = params.toString();
        const url = '/crm/v3' + path + (qs ? '?' + qs : '');
        window.location.assign(url);
        bridgeToast('goto ' + path, true);
        return true;
      } catch (e) {
        bridgeToast('goto MISS ' + path, false);
        return false;
      }
    }
    case 'ping': bridgeToast('ping ' + new URLSearchParams(location.search).size, true); return true;
    default: bridgeToast('unknown ' + verb, false); return false;
  }
}

function handleUrl(url) {
  try {
    const u = new URL(url);
    if (u.host !== 'uitest' && u.hostname !== 'uitest') return;
    const cmdParam = u.searchParams.get('cmd');
    if (!cmdParam) { bridgeToast('no cmd', false); return; }
    // Chain on ';'. Small delay between chained commands so React re-renders
    // between a nav tap and a follow-up scroll/focus.
    const cmds = cmdParam.split(';').map((c) => c.trim()).filter(Boolean);
    let i = 0;
    const step = () => {
      if (i >= cmds.length) return;
      runCommand(cmds[i]);
      i += 1;
      if (i < cmds.length) setTimeout(step, 500);
    };
    step();
  } catch (e) {
    bridgeToast('err ' + (e && e.message ? e.message : e), false);
  }
}

// Run a single command chain (';'-separated), spacing steps so React
// re-renders between a nav tap and a follow-up scroll/focus.
function runChain(cmdParam) {
  const cmds = cmdParam.split(';').map((c) => c.trim()).filter(Boolean);
  let i = 0;
  const step = () => {
    if (i >= cmds.length) return;
    runCommand(cmds[i]);
    i += 1;
    if (i < cmds.length) setTimeout(step, 500);
  };
  step();
}

if (isNative) {
  // CHANNEL 1 (fallback): custom-scheme deep link. Works but iOS shows an
  // "Open in BPP?" confirmation, so it is not the primary driver.
  CapApp.addListener('appUrlOpen', (data) => {
    if (data && data.url) handleUrl(data.url);
  });
  CapApp.getLaunchUrl().then((res) => {
    if (res && res.url) handleUrl(res.url);
  }).catch(() => { /* no-op */ });

  // CHANNEL 2 (primary, dialog-free): poll a command file served by the Vite
  // dev server. Only active in LIVE-RELOAD mode, detected by an http(s)
  // origin (bundled mode is capacitor://localhost, where the file can't be
  // updated without a rebuild, so polling is pointless and stays off). The
  // driver (sim.sh) writes {seq,cmd} to public/__uicmd.json; we run each new
  // seq exactly once. No confirmation dialog, no pixel coordinates.
  if (location.protocol === 'http:' || location.protocol === 'https:') {
    let lastSeq = -1;
    const poll = async () => {
      try {
        // Absolute under base so deep routes (thread/detail) do not resolve
        // relative to /crm/v3/tabs/.../__uicmd.json and miss the harness.
        const res = await fetch('/crm/v3/__uicmd.json?t=' + Date.now(), { cache: 'no-store' });
        if (res.ok) {
          const data = await res.json();
          if (typeof data.seq === 'number' && data.seq > lastSeq) {
            lastSeq = data.seq;
            if (data.cmd) runChain(String(data.cmd));
          }
        }
      } catch (_) { /* dev server not up yet, keep polling */ }
    };
    setInterval(poll, 400);
    bridgeToast('poll live', true);
  }
}
