// Runs BEFORE any of the 11 CRM source files import, because it's imported
// first from main.jsx and ES module import order preserves ordering. Pins the
// npm-bundled React / ReactDOM / Supabase onto window under the exact names
// the old UMD script tags used, so every bare `React.useState`,
// `ReactDOM.createRoot`, `React.createPortal`, and `window.supabase.createClient`
// reference across the 11 source files resolves against them.
//
// Why a separate module: `import` statements at the top of a module hoist and
// execute in order; they all run to completion BEFORE any subsequent code in
// the SAME module runs. If we did `window.React = React` in main.jsx after
// the react import but before the source-file imports, the source-file imports
// would still fire first, hitting `React is not defined` at load.

import * as React from 'react';
import * as ReactDOMLegacy from 'react-dom';
import * as ReactDOMClient from 'react-dom/client';
import * as supabaseNS from '@supabase/supabase-js';

// The old UMD `react-dom.development.js` shipped BOTH the legacy react-dom
// surface (createPortal, render, etc) AND the React 18 client entry
// (createRoot, hydrateRoot) on one global. In the ES module split those live
// at 'react-dom' and 'react-dom/client' respectively; merge them so every
// existing `ReactDOM.createRoot` and `ReactDOM.createPortal` call resolves
// verbatim.
const ReactDOM = { ...ReactDOMLegacy, ...ReactDOMClient };

if (typeof window !== 'undefined') {
  window.React = React;
  window.ReactDOM = ReactDOM;
  // The UMD supabase.js exposed a global `supabase` with `.createClient`. The
  // ES module namespace has the same shape, so `window.supabase.createClient(...)`
  // in crm-data.js still works verbatim.
  window.supabase = supabaseNS;
}
